-- =============================================================================
-- NetAgent Platform — Database Initialization
-- Gerado a partir de pg_dump da produção em 2026-04-21
-- Estrutura + seeds (plans, skills, knowledge_base). Tenants/users NÃO incluídos.
-- =============================================================================






CREATE EXTENSION IF NOT EXISTS pgcrypto WITH SCHEMA public;



COMMENT ON EXTENSION pgcrypto IS 'cryptographic functions';



CREATE EXTENSION IF NOT EXISTS "uuid-ossp" WITH SCHEMA public;



COMMENT ON EXTENSION "uuid-ossp" IS 'generate universally unique identifiers (UUIDs)';



CREATE EXTENSION IF NOT EXISTS vector WITH SCHEMA public;



COMMENT ON EXTENSION vector IS 'vector data type and ivfflat and hnsw access methods';





SET default_tablespace = '';

SET default_table_access_method = heap;


CREATE TABLE public.knowledge_base (
    id uuid DEFAULT gen_random_uuid() NOT NULL,
    title character varying(500) NOT NULL,
    content text NOT NULL,
    embedding public.vector(1536),
    category character varying(100),
    device_type character varying(50),
    source character varying(100) DEFAULT 'manual'::character varying NOT NULL,
    tenant_id uuid,
    quality_score double precision DEFAULT 0.5 NOT NULL,
    use_count integer DEFAULT 0 NOT NULL,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    CONSTRAINT knowledge_base_source_check CHECK (((source)::text = ANY ((ARRAY['manual'::character varying, 'learned'::character varying, 'documentation'::character varying])::text[])))
);



CREATE TABLE public.plans (
    id uuid DEFAULT gen_random_uuid() NOT NULL,
    name character varying(100) NOT NULL,
    max_devices integer DEFAULT 10 NOT NULL,
    max_users integer DEFAULT 5 NOT NULL,
    max_whatsapp_numbers integer DEFAULT 3 NOT NULL,
    price_monthly numeric(10,2),
    features jsonb DEFAULT '{}'::jsonb NOT NULL,
    active boolean DEFAULT true NOT NULL,
    created_at timestamp with time zone DEFAULT now() NOT NULL
);



CREATE TABLE public.platform_users (
    id uuid DEFAULT gen_random_uuid() NOT NULL,
    email character varying(255) NOT NULL,
    password_hash character varying(255) NOT NULL,
    role character varying(20) DEFAULT 'admin'::character varying NOT NULL,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    CONSTRAINT platform_users_role_check CHECK (((role)::text = ANY ((ARRAY['superadmin'::character varying, 'admin'::character varying])::text[])))
);



CREATE TABLE public.skill_tenant_overrides (
    skill_id uuid NOT NULL,
    tenant_id text NOT NULL,
    active boolean DEFAULT false NOT NULL
);



CREATE TABLE public.skills (
    id uuid DEFAULT gen_random_uuid() NOT NULL,
    name character varying(100) NOT NULL,
    display_name character varying(200) NOT NULL,
    description text NOT NULL,
    category character varying(50) NOT NULL,
    device_type character varying(50),
    prompt_template text,
    tools jsonb DEFAULT '[]'::jsonb NOT NULL,
    examples jsonb DEFAULT '[]'::jsonb NOT NULL,
    version integer DEFAULT 1 NOT NULL,
    active boolean DEFAULT true NOT NULL,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    steps jsonb DEFAULT '[]'::jsonb NOT NULL
);



CREATE TABLE public.tenants (
    id uuid DEFAULT gen_random_uuid() NOT NULL,
    name character varying(255) NOT NULL,
    slug character varying(100) NOT NULL,
    plan_id uuid,
    evolution_instance character varying(100),
    evolution_key character varying(255),
    openai_key_encrypted character varying(500),
    gpt_model character varying(50) DEFAULT 'gpt-4o'::character varying NOT NULL,
    admin_email character varying(255) NOT NULL,
    active boolean DEFAULT true NOT NULL,
    trial_ends_at timestamp with time zone,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    wg_subnet character varying(20),
    wg_port integer,
    wg_private_key text,
    wg_public_key text
);



ALTER TABLE ONLY public.knowledge_base
    ADD CONSTRAINT knowledge_base_pkey PRIMARY KEY (id);



ALTER TABLE ONLY public.plans
    ADD CONSTRAINT plans_pkey PRIMARY KEY (id);



ALTER TABLE ONLY public.platform_users
    ADD CONSTRAINT platform_users_email_key UNIQUE (email);



ALTER TABLE ONLY public.platform_users
    ADD CONSTRAINT platform_users_pkey PRIMARY KEY (id);



ALTER TABLE ONLY public.skill_tenant_overrides
    ADD CONSTRAINT skill_tenant_overrides_pkey PRIMARY KEY (skill_id, tenant_id);



ALTER TABLE ONLY public.skills
    ADD CONSTRAINT skills_name_key UNIQUE (name);



ALTER TABLE ONLY public.skills
    ADD CONSTRAINT skills_pkey PRIMARY KEY (id);



ALTER TABLE ONLY public.tenants
    ADD CONSTRAINT tenants_pkey PRIMARY KEY (id);



ALTER TABLE ONLY public.tenants
    ADD CONSTRAINT tenants_slug_key UNIQUE (slug);



CREATE INDEX idx_sto_tenant ON public.skill_tenant_overrides USING btree (tenant_id);



CREATE INDEX knowledge_base_category_idx ON public.knowledge_base USING btree (category);



CREATE INDEX knowledge_base_device_type_idx ON public.knowledge_base USING btree (device_type);



CREATE INDEX knowledge_base_embedding_idx ON public.knowledge_base USING ivfflat (embedding public.vector_cosine_ops) WITH (lists='100');



ALTER TABLE ONLY public.knowledge_base
    ADD CONSTRAINT knowledge_base_tenant_id_fkey FOREIGN KEY (tenant_id) REFERENCES public.tenants(id);



ALTER TABLE ONLY public.skill_tenant_overrides
    ADD CONSTRAINT skill_tenant_overrides_skill_id_fkey FOREIGN KEY (skill_id) REFERENCES public.skills(id) ON DELETE CASCADE;



ALTER TABLE ONLY public.tenants
    ADD CONSTRAINT tenants_plan_id_fkey FOREIGN KEY (plan_id) REFERENCES public.plans(id);

-- =============================================================================
-- FUNÇÃO: public.create_tenant_schema(slug text)
-- DDL gerada do schema real do tenant de produção (forumtelecom).
-- Clona estrutura completa de 15 tabelas + PKs + UKs + FKs + 1 índice.
-- =============================================================================
CREATE OR REPLACE FUNCTION public.create_tenant_schema(slug text) RETURNS void
LANGUAGE plpgsql AS $fn$
DECLARE
  ddl text;
BEGIN
  EXECUTE format('CREATE SCHEMA IF NOT EXISTS %I', slug);
  ddl := replace($TMPL$
CREATE TABLE forumtelecom.automations (
    id uuid DEFAULT public.uuid_generate_v4() NOT NULL,
    name character varying(255) NOT NULL,
    skill_id uuid NOT NULL,
    target_devices jsonb DEFAULT '[]'::jsonb,
    cron_expression character varying(50) NOT NULL,
    is_active boolean DEFAULT true,
    notification_target character varying(100) DEFAULT 'default'::character varying,
    last_run_at timestamp with time zone,
    last_status character varying(50),
    created_at timestamp with time zone DEFAULT now(),
    updated_at timestamp with time zone DEFAULT now()
);



CREATE TABLE forumtelecom.conversations (
    id uuid DEFAULT public.uuid_generate_v4() NOT NULL,
    channel character varying(20) DEFAULT 'web'::character varying,
    whatsapp_number character varying(20),
    web_user_id uuid,
    title character varying(255),
    started_at timestamp with time zone DEFAULT now(),
    last_activity_at timestamp with time zone DEFAULT now()
);



CREATE TABLE forumtelecom.device_snapshots (
    id uuid DEFAULT gen_random_uuid() NOT NULL,
    device_id uuid NOT NULL,
    captured_at timestamp with time zone DEFAULT now(),
    os_info text,
    services jsonb DEFAULT '[]'::jsonb,
    installed_pkgs jsonb DEFAULT '[]'::jsonb,
    open_ports jsonb DEFAULT '[]'::jsonb,
    disk_info text,
    extra jsonb DEFAULT '{}'::jsonb,
    notes text
);



CREATE TABLE forumtelecom.devices (
    id uuid DEFAULT public.uuid_generate_v4() NOT NULL,
    name character varying(100) NOT NULL,
    type character varying(50) NOT NULL,
    host character varying(255) NOT NULL,
    port integer DEFAULT 22,
    username character varying(100) NOT NULL,
    password_encrypted text,
    description text,
    location character varying(255),
    tags jsonb DEFAULT '[]'::jsonb,
    active boolean DEFAULT true,
    last_seen_at timestamp with time zone,
    created_at timestamp with time zone DEFAULT now()
);



CREATE TABLE forumtelecom.mcp_drivers (
    id uuid DEFAULT public.uuid_generate_v4() NOT NULL,
    name character varying(100) NOT NULL,
    url character varying(500) NOT NULL,
    device_type character varying(50) NOT NULL,
    scopes jsonb DEFAULT '[]'::jsonb,
    transport character varying(20) DEFAULT 'streamable-http'::character varying,
    health_endpoint character varying(100) DEFAULT '/health'::character varying,
    mcp_endpoint character varying(100) DEFAULT '/mcp'::character varying,
    status character varying(20) DEFAULT 'offline'::character varying,
    circuit_config jsonb DEFAULT '{"call_timeout_s": 15, "failure_threshold": 3, "recovery_timeout_s": 30}'::jsonb,
    active boolean DEFAULT true,
    last_health_check timestamp with time zone,
    created_at timestamp with time zone DEFAULT now(),
    updated_at timestamp with time zone DEFAULT now()
);



CREATE TABLE forumtelecom.messages (
    id uuid DEFAULT public.uuid_generate_v4() NOT NULL,
    conversation_id uuid NOT NULL,
    role character varying(20) NOT NULL,
    content text NOT NULL,
    device_id uuid,
    tool_calls jsonb DEFAULT '[]'::jsonb,
    reasoning jsonb DEFAULT '[]'::jsonb,
    audio_url text,
    tokens_used integer DEFAULT 0,
    created_at timestamp with time zone DEFAULT now(),
    pending_action_id uuid
);



CREATE TABLE forumtelecom.pending_actions (
    id uuid DEFAULT public.uuid_generate_v4() NOT NULL,
    conversation_id uuid,
    device_id uuid,
    description text NOT NULL,
    impact_analysis text,
    commands jsonb DEFAULT '[]'::jsonb,
    status character varying(20) DEFAULT 'pending'::character varying,
    requested_at timestamp with time zone DEFAULT now(),
    resolved_at timestamp with time zone,
    resolved_by text,
    action_type character varying(50),
    risk_level character varying(20) DEFAULT 'medium'::character varying
);



CREATE TABLE forumtelecom.settings (
    key character varying(100) NOT NULL,
    value text NOT NULL,
    encrypted boolean DEFAULT false,
    updated_at timestamp with time zone DEFAULT now()
);



CREATE TABLE forumtelecom.tenant_memories (
    id uuid DEFAULT gen_random_uuid() NOT NULL,
    conversation_id uuid,
    device_id uuid,
    memory_type character varying(50) NOT NULL,
    content text NOT NULL,
    embedding public.vector(1536),
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    CONSTRAINT tenant_memories_memory_type_check CHECK (((memory_type)::text = ANY ((ARRAY['user_preference'::character varying, 'device_fact'::character varying, 'network_topology'::character varying, 'misc'::character varying])::text[])))
);



CREATE TABLE forumtelecom.users (
    id uuid DEFAULT public.uuid_generate_v4() NOT NULL,
    email character varying(255) NOT NULL,
    password_hash text NOT NULL,
    name character varying(255),
    role character varying(20) DEFAULT 'operator'::character varying,
    active boolean DEFAULT true,
    last_login_at timestamp with time zone,
    created_at timestamp with time zone DEFAULT now()
);



CREATE TABLE forumtelecom.whatsapp_users (
    id uuid DEFAULT public.uuid_generate_v4() NOT NULL,
    number character varying(20) NOT NULL,
    name character varying(255),
    role character varying(20) DEFAULT 'operator'::character varying,
    active boolean DEFAULT true,
    created_at timestamp with time zone DEFAULT now()
);



CREATE TABLE forumtelecom.wireguard_interfaces (
    id uuid DEFAULT gen_random_uuid() NOT NULL,
    device_id uuid NOT NULL,
    name character varying(100) NOT NULL,
    listen_port integer NOT NULL,
    private_key text NOT NULL,
    public_key text NOT NULL,
    comment text,
    active boolean DEFAULT true NOT NULL,
    created_at timestamp with time zone DEFAULT now() NOT NULL
);



CREATE TABLE forumtelecom.wireguard_peers (
    id uuid DEFAULT gen_random_uuid() NOT NULL,
    interface_id uuid NOT NULL,
    name character varying(100) NOT NULL,
    public_key text NOT NULL,
    private_key text,
    preshared_key text,
    allowed_address text NOT NULL,
    persistent_keepalive integer,
    endpoint text,
    download_bandwidth bigint,
    upload_bandwidth bigint,
    traffic_limit bigint,
    download_usage bigint DEFAULT 0 NOT NULL,
    upload_usage bigint DEFAULT 0 NOT NULL,
    expire_time timestamp with time zone,
    comment text,
    active boolean DEFAULT true NOT NULL,
    is_shared boolean DEFAULT false NOT NULL,
    share_expire_time timestamp with time zone,
    created_at timestamp with time zone DEFAULT now() NOT NULL
);



CREATE TABLE forumtelecom.wireguard_pools (
    id uuid DEFAULT gen_random_uuid() NOT NULL,
    interface_id uuid NOT NULL,
    name character varying(100) NOT NULL,
    start_ip character varying(50) NOT NULL,
    end_ip character varying(50) NOT NULL,
    created_at timestamp with time zone DEFAULT now() NOT NULL
);



CREATE TABLE forumtelecom.wireguard_server_peers (
    id uuid DEFAULT gen_random_uuid() NOT NULL,
    device_id uuid,
    name character varying(100) NOT NULL,
    public_key text NOT NULL,
    private_key text,
    preshared_key text,
    ip_address character varying(50) NOT NULL,
    active boolean DEFAULT true NOT NULL,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    os_type character varying(20) DEFAULT 'mikrotik'::character varying
);



ALTER TABLE ONLY forumtelecom.automations
    ADD CONSTRAINT automations_pkey PRIMARY KEY (id);



ALTER TABLE ONLY forumtelecom.conversations
    ADD CONSTRAINT conversations_pkey PRIMARY KEY (id);



ALTER TABLE ONLY forumtelecom.device_snapshots
    ADD CONSTRAINT device_snapshots_pkey PRIMARY KEY (id);



ALTER TABLE ONLY forumtelecom.devices
    ADD CONSTRAINT devices_pkey PRIMARY KEY (id);



ALTER TABLE ONLY forumtelecom.mcp_drivers
    ADD CONSTRAINT mcp_drivers_name_key UNIQUE (name);



ALTER TABLE ONLY forumtelecom.mcp_drivers
    ADD CONSTRAINT mcp_drivers_pkey PRIMARY KEY (id);



ALTER TABLE ONLY forumtelecom.messages
    ADD CONSTRAINT messages_pkey PRIMARY KEY (id);



ALTER TABLE ONLY forumtelecom.pending_actions
    ADD CONSTRAINT pending_actions_pkey PRIMARY KEY (id);



ALTER TABLE ONLY forumtelecom.settings
    ADD CONSTRAINT settings_pkey PRIMARY KEY (key);



ALTER TABLE ONLY forumtelecom.tenant_memories
    ADD CONSTRAINT tenant_memories_pkey PRIMARY KEY (id);



ALTER TABLE ONLY forumtelecom.users
    ADD CONSTRAINT users_email_key UNIQUE (email);



ALTER TABLE ONLY forumtelecom.users
    ADD CONSTRAINT users_pkey PRIMARY KEY (id);



ALTER TABLE ONLY forumtelecom.whatsapp_users
    ADD CONSTRAINT whatsapp_users_number_key UNIQUE (number);



ALTER TABLE ONLY forumtelecom.whatsapp_users
    ADD CONSTRAINT whatsapp_users_pkey PRIMARY KEY (id);



ALTER TABLE ONLY forumtelecom.wireguard_interfaces
    ADD CONSTRAINT wireguard_interfaces_device_id_name_key UNIQUE (device_id, name);



ALTER TABLE ONLY forumtelecom.wireguard_interfaces
    ADD CONSTRAINT wireguard_interfaces_pkey PRIMARY KEY (id);



ALTER TABLE ONLY forumtelecom.wireguard_peers
    ADD CONSTRAINT wireguard_peers_interface_id_name_key UNIQUE (interface_id, name);



ALTER TABLE ONLY forumtelecom.wireguard_peers
    ADD CONSTRAINT wireguard_peers_interface_id_public_key_key UNIQUE (interface_id, public_key);



ALTER TABLE ONLY forumtelecom.wireguard_peers
    ADD CONSTRAINT wireguard_peers_pkey PRIMARY KEY (id);



ALTER TABLE ONLY forumtelecom.wireguard_pools
    ADD CONSTRAINT wireguard_pools_pkey PRIMARY KEY (id);



ALTER TABLE ONLY forumtelecom.wireguard_server_peers
    ADD CONSTRAINT wireguard_server_peers_ip_address_key UNIQUE (ip_address);



ALTER TABLE ONLY forumtelecom.wireguard_server_peers
    ADD CONSTRAINT wireguard_server_peers_name_key UNIQUE (name);



ALTER TABLE ONLY forumtelecom.wireguard_server_peers
    ADD CONSTRAINT wireguard_server_peers_pkey PRIMARY KEY (id);



ALTER TABLE ONLY forumtelecom.wireguard_server_peers
    ADD CONSTRAINT wireguard_server_peers_public_key_key UNIQUE (public_key);



CREATE INDEX idx_ds_device_time ON forumtelecom.device_snapshots USING btree (device_id, captured_at DESC);



ALTER TABLE ONLY forumtelecom.automations
    ADD CONSTRAINT automations_skill_id_fkey FOREIGN KEY (skill_id) REFERENCES public.skills(id) ON DELETE CASCADE;



ALTER TABLE ONLY forumtelecom.tenant_memories
    ADD CONSTRAINT tenant_memories_conversation_id_fkey FOREIGN KEY (conversation_id) REFERENCES forumtelecom.conversations(id) ON DELETE SET NULL;



ALTER TABLE ONLY forumtelecom.tenant_memories
    ADD CONSTRAINT tenant_memories_device_id_fkey FOREIGN KEY (device_id) REFERENCES forumtelecom.devices(id) ON DELETE CASCADE;



ALTER TABLE ONLY forumtelecom.wireguard_interfaces
    ADD CONSTRAINT wireguard_interfaces_device_id_fkey FOREIGN KEY (device_id) REFERENCES forumtelecom.devices(id) ON DELETE CASCADE;



ALTER TABLE ONLY forumtelecom.wireguard_peers
    ADD CONSTRAINT wireguard_peers_interface_id_fkey FOREIGN KEY (interface_id) REFERENCES forumtelecom.wireguard_interfaces(id) ON DELETE CASCADE;



ALTER TABLE ONLY forumtelecom.wireguard_pools
    ADD CONSTRAINT wireguard_pools_interface_id_fkey FOREIGN KEY (interface_id) REFERENCES forumtelecom.wireguard_interfaces(id) ON DELETE CASCADE;



ALTER TABLE ONLY forumtelecom.wireguard_server_peers
    ADD CONSTRAINT wireguard_server_peers_device_id_fkey FOREIGN KEY (device_id) REFERENCES forumtelecom.devices(id) ON DELETE CASCADE;
$TMPL$, 'forumtelecom', slug);
  EXECUTE ddl;

  -- Default settings (tenant-scoped)
  EXECUTE format($SETTINGS$
    INSERT INTO %I.settings (key, value) VALUES
      ('alert_cpu_threshold',    '85'),
      ('alert_check_interval',   '60'),
      ('daily_report_hour',      '8'),
      ('daily_report_enabled',   'true'),
      ('require_approval_for',   '["reboot","delete","firewall","vpn"]'),
      ('language',               'pt-BR')
    ON CONFLICT (key) DO NOTHING
  $SETTINGS$, slug);

  RAISE NOTICE 'Tenant schema % created successfully.', slug;
END;
$fn$;

COMMENT ON FUNCTION public.create_tenant_schema(text) IS
  'Creates a full tenant schema cloned from production template. Usage: SELECT public.create_tenant_schema(''my-slug'');';

-- =============================================================================
-- Seeds — plans, skills, knowledge_base (copiado da produção)
-- =============================================================================






